34	  <link rel="icon" type="image/svg+xml" href="data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'><text y='.9em' font-size='90'>🧪</text></svg>">
35	  
36	  <style>
37	    /* === DEN BRAND SYSTEM === */
38	    :root {
39	      /* Colors - Inspired by vintage scientific equipment & space programs */
40	      --bg-primary: #0D1117;
41	      --bg-secondary: #161B22;
42	      --bg-tertiary: #21262D;
43	      
44	      --accent-orange: #FF6B35;
45	      --accent-amber: #F4A261;
46	      --accent-teal: #2A9D8F;
47	      --accent-cyan: #4CC9F0;
48	      --accent-lime: #B5E48C;
49	      --accent-red: #E63946;
50	      
51	      --text-primary: #E6EDF3;
52	      --text-secondary: #7D8597;
53	      --text-muted: #484F58;
54	      
55	      /* Typography */
56	      --font-mono: "SF Mono", Monaco, "Cascadia Code", "Roboto Mono", Consolas, monospace;
57	      --font-sans: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
58	      
59	      /* Spacing */
60	      --space-xs: 0.5rem;
61	      --space-sm: 0.75rem;
62	      --space-md: 1rem;
63	      --space-lg: 1.5rem;
64	      --space-xl: 2rem;
65	      --space-2xl: 3rem;
66	      --space-3xl: 4rem;
67	      
68	      /* Radii */
69	      --radius-sm: 4px;
70	      --radius-md: 6px;
71	      --radius-lg: 8px;
72	    }
73	    
74	    * {
75	      margin: 0;
76	      padding: 0;
77	      box-sizing: border-box;
78	    }
79	    
80	    html {
81	      scroll-behavior: smooth;
82	    }
83	    
84	    body {
85	      font-family: var(--font-sans);
86	      background: var(--bg-primary);
87	      color: var(--text-primary);
88	      line-height: 1.6;
89	      min-height: 100vh;
90	      overflow-x: hidden;
91	    }
92	    
93	    /* === SCANLINE OVERLAY === */
94	    body::before {
95	      content: "";
96	      position: fixed;
97	      top: 0;
98	      left: 0;
99	      width: 100%;
100	      height: 100%;
101	      background: repeating-linear-gradient(
102	        0deg,
103	        transparent,
104	        transparent 2px,
105	        rgba(0,0,0,0.03) 2px,
106	        rgba(0,0,0,0.03) 4px
107	      );
108	      pointer-events: none;
109	      z-index: 1000;
110	    }
111	    
112	    /* === NAVIGATION === */
113	    nav {
114	      position: fixed;
115	      top: 0;
116	      left: 0;
117	      right: 0;
118	      padding: var(--space-md) var(--space-xl);
119	      display: flex;
120	      justify-content: space-between;
121	      align-items: center;
122	      z-index: 100;
123	      background: rgba(13, 17, 23, 0.8);
124	      backdrop-filter: blur(10px);
125	      border-bottom: 1px solid var(--bg-tertiary);
126	    }
127	    
128	    .logo {
129	      display: flex;
130	      align-items: center;
131	      gap: var(--space-sm);
132	      font-family: var(--font-mono);
133	      font-size: 1.25rem;
134	      font-weight: 600;
135	      color: var(--accent-orange);
136	      text-decoration: none;
137	    }
138	    
139	    .logo-icon {
140	      font-size: 1.5rem;
141	    }
142	    
143	    .nav-links {
144	      display: flex;
145	      gap: var(--space-lg);
146	      list-style: none;
147	    }
148	    
149	    .nav-links a {
150	      color: var(--text-secondary);
151	      text-decoration: none;
152	      font-family: var(--font-mono);
153	      font-size: 0.875rem;
154	      transition: color 0.2s;
155	    }
156	    
157	    .nav-links a:hover {
158	      color: var(--accent-orange);
159	    }
160	    
161	    /* === HERO === */
162	    .hero {
163	      min-height: 100vh;
164	      display: flex;
165	      flex-direction: column;
166	      justify-content: center;
167	      align-items: center;
168	      text-align: center;
169	      padding: var(--space-3xl) var(--space-xl);
170	      position: relative;
171	      overflow: hidden;
172	    }
173	    
174	    /* Decorative grid background */
175	    .hero::before {
176	      content: "";
177	      position: absolute;
178	      top: 50%;
179	      left: 50%;
180	      transform: translate(-50%, -50%);
181	      width: 200%;
182	      height: 200%;
183	      background-image: 
184	        linear-gradient(var(--bg-tertiary) 1px, transparent 1px),
185	        linear-gradient(90deg, var(--bg-tertiary) 1px, transparent 1px);
186	      background-size: 60px 60px;
187	      opacity: 0.3;
188	      animation: gridMove 20s linear infinite;
189	      pointer-events: none;
190	    }
191	    
192	    @keyframes gridMove {
193	      0% { transform: translate(-50%, -50%) translate(0, 0); }
194	      100% { transform: translate(-50%, -50%) translate(60px, 60px); }
195	    }
196	    
197	    .hero-content {
198	      position: relative;
199	      z-index: 1;
200	    }
201	    
202	    .hero-badge {
203	      display: inline-flex;
204	      align-items: center;
205	      gap: var(--space-xs);
206	      padding: var(--space-xs) var(--space-md);
207	      background: var(--bg-secondary);
208	      border: 1px solid var(--bg-tertiary);
209	      border-radius: var(--radius-lg);
210	      font-family: var(--font-mono);
211	      font-size: 0.75rem;
212	      color: var(--accent-amber);
213	      margin-bottom: var(--space-lg);
214	    }
215	    
216	    .hero-badge .dot {
217	      width: 8px;
218	      height: 8px;
219	      background: var(--accent-lime);
220	      border-radius: 50%;
221	      animation: pulse 2s ease-in-out infinite;
222	    }
223	    
224	    @keyframes pulse {
225	      0%, 100% { opacity: 1; }
226	      50% { opacity: 0.5; }
227	    }
228	    
229	    h1 {
230	      font-size: clamp(3rem, 8vw, 6rem);
231	      font-weight: 800;
232	      letter-spacing: -0.03em;
233	      line-height: 1;
234	      margin-bottom: var(--space-md);
235	      background: linear-gradient(135deg, var(--text-primary) 0%, var(--accent-orange) 100%);
236	      -webkit-background-clip: text;
237	      -webkit-text-fill-color: transparent;
238	      background-clip: text;
239	    }
240	    
241	    .hero-tagline {
242	      font-size: clamp(1.125rem, 2.5vw, 1.5rem);
243	      color: var(--text-secondary);
244	      max-width: 600px;
245	      margin-bottom: var(--space-2xl);
246	    }
247	    
248	    .hero-actions {
249	      display: flex;
250	      gap: var(--space-md);
251	      flex-wrap: wrap;
252	      justify-content: center;
253	    }
254	    
255	    /* === BUTTONS === */
256	    .btn {
257	      display: inline-flex;
258	      align-items: center;
259	      gap: var(--space-sm);
260	      padding: var(--space-md) var(--space-xl);
261	      font-family: var(--font-mono);
262	      font-size: 0.875rem;
263	      font-weight: 500;
264	      text-decoration: none;
265	      border-radius: var(--radius-md);
266	      transition: all 0.2s;
267	      cursor: pointer;
268	      border: none;
269	    }
270	    
271	    .btn-primary {
272	      background: var(--accent-orange);
273	      color: var(--bg-primary);
274	    }
275	    
276	    .btn-primary:hover {
277	      background: var(--accent-amber);
278	      transform: translateY(-2px);
279	      box-shadow: 0 4px 20px rgba(255, 107, 53, 0.3);
280	    }
281	    
282	    .btn-secondary {
283	      background: transparent;
284	      color: var(--text-primary);
285	      border: 1px solid var(--bg-tertiary);
286	    }
287	    
288	    .btn-secondary:hover {
289	      border-color: var(--accent-orange);
290	      color: var(--accent-orange);
291	    }
292	    
293	    /* === TERMINAL === */
294	    .terminal {
295	      max-width: 800px;
296	      width: 100%;
297	      margin: var(--space-3xl) auto 0;
298	      background: var(--bg-secondary);
299	      border-radius: var(--radius-lg);
300	      border: 1px solid var(--bg-tertiary);
301	      overflow: hidden;
302	      position: relative;
303	      z-index: 1;
304	    }
305	    
306	    .terminal-header {
307	      display: flex;
308	      align-items: center;
309	      gap: var(--space-sm);
310	      padding: var(--space-sm) var(--space-md);
311	      background: var(--bg-tertiary);
312	      border-bottom: 1px solid var(--bg-tertiary);
313	    }
314	    
315	    .terminal-dot {
316	      width: 12px;
317	      height: 12px;
318	      border-radius: 50%;
319	    }
320	    
321	    .terminal-dot.red { background: var(--accent-red); }
322	    .terminal-dot.yellow { background: var(--accent-amber); }
323	    .terminal-dot.green { background: var(--accent-lime); }
324	    
325	    .terminal-title {
326	      margin-left: auto;
327	      font-family: var(--font-mono);
328	      font-size: 0.75rem;
329	      color: var(--text-muted);
330	    }
331	    
332	    .terminal-body {
333	      padding: var(--space-lg);
334	      font-family: var(--font-mono);
335	      font-size: 0.875rem;
336	      line-height: 1.8;
337	      overflow-x: auto;
338	    }
339	    
340	    .terminal-line {
341	      display: flex;
342	      gap: var(--space-sm);
343	    }
344	    
345	    .terminal-prompt {
346	      color: var(--accent-orange);
347	    }
348	    
349	    .terminal-command {
350	      color: var(--text-primary);
351	    }
352	    
353	    .terminal-output {
354	      color: var(--text-secondary);
355	      margin-top: var(--space-xs);
356	      margin-bottom: var(--space-md);
357	    }
358	    
359	    .terminal-output.success {
360	      color: var(--accent-lime);
361	    }
362	    
363	    .terminal-cursor {
364	      display: inline-block;
365	      width: 8px;
366	      height: 1.2em;
367	      background: var(--accent-orange);
368	      animation: blink 1s step-end infinite;
369	      vertical-align: middle;
370	    }
371	    
372	    @keyframes blink {
373	      0%, 50% { opacity: 1; }
374	      51%, 100% { opacity: 0; }
375	    }
376	    
377	    /* === SECTIONS === */
378	    section {
379	      padding: var(--space-3xl) var(--space-xl);
380	      max-width: 1200px;
381	      margin: 0 auto;
382	    }
383	    
384	    .section-header {
385	      text-align: center;
386	      margin-bottom: var(--space-3xl);
387	    }
388	    
389	    .section-label {
390	      display: inline-block;
391	      font-family: var(--font-mono);
392	      font-size: 0.75rem;
393	      color: var(--accent-orange);
394	      text-transform: uppercase;
395	      letter-spacing: 0.1em;
396	      margin-bottom: var(--space-sm);
397	    }
398	    
399	    h2 {
400	      font-size: clamp(1.75rem, 4vw, 2.5rem);
401	      font-weight: 700;
402	      letter-spacing: -0.02em;
403	      margin-bottom: var(--space-md);
404	    }
405	    
406	    .section-desc {
407	      color: var(--text-secondary);
408	      max-width: 600px;
409	      margin: 0 auto;
410	    }
411	    
412	    /* === FEATURES === */
413	    .features {
414	      display: grid;
415	      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
416	      gap: var(--space-lg);
417	    }
418	    
419	    .feature {
420	      background: var(--bg-secondary);
421	      border: 1px solid var(--bg-tertiary);
422	      border-radius: var(--radius-lg);
423	      padding: var(--space-xl);
424	      transition: all 0.2s;
425	      position: relative;
426	    }
427	    
428	    .feature:hover {
429	      border-color: var(--accent-orange);
430	      transform: translateY(-4px);
431	    }
432	    
433	    .feature::before {
434	      content: "";
435	      position: absolute;
436	      top: 0;
437	      left: 0;
438	      right: 0;
439	      height: 2px;
440	      background: linear-gradient(90deg, var(--accent-orange), var(--accent-amber));
441	      opacity: 0;
442	      transition: opacity 0.2s;
443	    }
444	    
445	    .feature:hover::before {
446	      opacity: 1;
447	    }
448	    
449	    .feature-icon {
450	      font-size: 2rem;
451	      margin-bottom: var(--space-md);
452	    }
453	    
454	    .feature h3 {
455	      font-size: 1.125rem;
456	      font-weight: 600;
457	      margin-bottom: var(--space-sm);
458	      color: var(--text-primary);
459	    }
460	    
461	    .feature p {
462	      color: var(--text-secondary);
463	      font-size: 0.875rem;
464	      line-height: 1.7;
465	    }
466	    
467	    .feature-meta {
468	      display: flex;
469	      gap: var(--space-sm);
470	      margin-top: var(--space-md);
471	      flex-wrap: wrap;
472	    }
473	    
474	    .feature-tag {
475	      font-family: var(--font-mono);
476	      font-size: 0.75rem;
477	      padding: 2px 8px;
478	      background: var(--bg-tertiary);
479	      color: var(--accent-cyan);
480	      border-radius: var(--radius-sm);
481	    }
482	    
483	    /* === INSTALL === */
484	    .install-grid {
485	      display: grid;
486	      grid-template-columns: 1fr 1fr;
487	      gap: var(--space-2xl);
488	      align-items: start;
489	    }
490	    
491	    @media (max-width: 768px) {
492	      .install-grid {
493	        grid-template-columns: 1fr;
494	      }
495	    }
496	    
497	    .install-card {
498	      background: var(--bg-secondary);
499	      border: 1px solid var(--bg-tertiary);
500	      border-radius: var(--radius-lg);
501	      padding: var(--space-xl);
502	    }
503	    
504	    .install-card h3 {
505	      font-size: 1rem;
506	      font-weight: 600;
507	      margin-bottom: var(--space-lg);
508	      display: flex;
509	      align-items: center;
510	      gap: var(--space-sm);
511	    }
512	    
513	    .install-card h3 span {
514	      font-size: 1.5rem;
515	    }
516	    
517	    .code-block {
518	      background: var(--bg-primary);
519	      border: 1px solid var(--bg-tertiary);
520	      border-radius: var(--radius-md);
521	      padding: var(--space-md);
522	      font-family: var(--font-mono);
523	      font-size: 0.8125rem;
524	      overflow-x: auto;
525	      margin-bottom: var(--space-md);
526	    }
527	    
528	    .code-block code {
529	      color: var(--accent-lime);
530	    }
531	    
532	    .code-block .comment {
533	      color: var(--text-muted);
534	    }
535	    
536	    .code-block .prompt {
537	      color: var(--accent-orange);
538	    }
539	    
540	    .prereq-list {
541	      list-style: none;
542	      font-size: 0.875rem;
543	      color: var(--text-secondary);
544	    }
545	    
546	    .prereq-list li {
547	      display: flex;
548	      align-items: center;
549	      gap: var(--space-sm);
550	      margin-bottom: var(--space-sm);
551	    }
552	    
553	    .prereq-list li::before {
554	      content: "✓";
555	      color: var(--accent-lime);
556	      font-weight: bold;
557	    }
558	    
559	    /* === USE CASES === */
560	    .use-cases {
561	      display: flex;
562	      flex-direction: column;
563	      gap: var(--space-xl);
564	    }
565	    
566	    .use-case {
567	      display: grid;
568	      grid-template-columns: auto 1fr;
569	      gap: var(--space-xl);
570	      padding: var(--space-xl);
571	      background: var(--bg-secondary);
572	      border: 1px solid var(--bg-tertiary);
573	      border-radius: var(--radius-lg);
574	      align-items: start;
575	    }
576	    
577	    @media (max-width: 600px) {
578	      .use-case {
579	        grid-template-columns: 1fr;
580	      }
581	    }
582	    
583	    .use-case-number {
584	      font-family: var(--font-mono);
585	      font-size: 3rem;
586	      font-weight: 800;
587	      color: var(--bg-tertiary);
588	      line-height: 1;
589	    }
590	    
591	    .use-case h3 {
592	      font-size: 1.25rem;
593	      font-weight: 600;
594	      margin-bottom: var(--space-sm);
595	    }
596	    
597	    .use-case p {
598	      color: var(--text-secondary);
599	      margin-bottom: var(--space-md);
600	    }
601	    
602	    .use-case-example {
603	      font-family: var(--font-mono);
604	      font-size: 0.8125rem;
605	      padding: var(--space-md);
606	      background: var(--bg-primary);
607	      border-radius: var(--radius-md);
608	      color: var(--accent-cyan);
609	    }
610	    
611	    /* === SOURCE CODE === */
612	    .source-section {
613	      text-align: center;
614	      background: var(--bg-secondary);
615	      border: 1px solid var(--bg-tertiary);
616	      border-radius: var(--radius-lg);
617	      padding: var(--space-3xl) var(--space-xl);
618	    }
619	    
620	    .source-section h2 {
621	      margin-bottom: var(--space-lg);
622	    }
623	    
624	    .source-section p {
625	      color: var(--text-secondary);
626	      margin-bottom: var(--space-xl);
627	      max-width: 500px;
628	      margin-left: auto;
629	      margin-right: auto;
630	    }
631	    
632	    .source-stats {
633	      display: flex;
634	      justify-content: center;
635	      gap: var(--space-3xl);
636	      margin-top: var(--space-xl);
637	      flex-wrap: wrap;
638	    }
639	    
640	    .stat {
641	      text-align: center;
642	    }
643	    
644	    .stat-value {
645	      font-family: var(--font-mono);
646	      font-size: 2rem;
647	      font-weight: 700;
648	      color: var(--accent-orange);
649	    }
650	    
651	    .stat-label {
652	      font-size: 0.875rem;
653	      color: var(--text-secondary);
654	    }
655	    
656	    /* === FOOTER === */
657	    footer {
658	      border-top: 1px solid var(--bg-tertiary);
659	      padding: var(--space-2xl) var(--space-xl);
660	      text-align: center;
661	    }
662	    
663	    .footer-content {
664	      max-width: 1200px;
665	      margin: 0 auto;
666	      display: flex;
667	      flex-direction: column;
668	      gap: var(--space-lg);
669	    }
670	    
671	    .footer-links {
672	      display: flex;
673	      justify-content: center;
674	      gap: var(--space-xl);
675	      flex-wrap: wrap;
676	    }
677	    
678	    .footer-links a {
679	      color: var(--text-secondary);
680	      text-decoration: none;
681	      font-family: var(--font-mono);
682	      font-size: 0.875rem;
683	      transition: color 0.2s;
684	    }
685	    
686	    .footer-links a:hover {
687	      color: var(--accent-orange);
688	    }
689	    
690	    .footer-copy {
691	      font-size: 0.875rem;
692	      color: var(--text-muted);
693	    }
694	    
695	    /* === SCROLLBAR === */
696	    ::-webkit-scrollbar {
697	      width: 8px;
698	      height: 8px;
699	    }
700	    
701	    ::-webkit-scrollbar-track {
702	      background: var(--bg-primary);
703	    }
704	    
705	    ::-webkit-scrollbar-thumb {
706	      background: var(--bg-tertiary);
707	      border-radius: 4px;
